private String trimZero(String str) {
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) != '0') {
            return str.substring(i);
        }
    }
    return str;
}

public String readFile(String fileName) throws IOException {
    try (BufferedReader br = new BufferedReader(new FileReader(fileName))) {
        StringBuilder sb = new StringBuilder();
        String line = br.readLine();

        while (line != null) {
            sb.append(line);
            sb.append("\n");
            line = br.readLine();
        }
        return sb.toString();
    }
}

public Map<String, BigDecimal> readStandardPercentage(String apname) {
    Map<String, BigDecimal> standardPercentage = new HashMap<>(); //skuSuffix -> standard percentage
    APIQuery aq = new APIQuery(apname, "/pricing", 2);
    aq.setUpdateMode();
    APIResultsFull ar = aq.getAPIResultsFull();
    for (APIEntry e : ar) {
        String skuSuffix = e.getFieldValue(1002512);
        String phw_price = e.getFieldValue(1002514);
        String phw_mon1 = e.getFieldValue(1003152);
        String phw_yr1 = e.getFieldValue(1002515);
        String phw_yr2 = e.getFieldValue(1002516);
        String phw_yr3 = e.getFieldValue(1002517);
        String phw_yr4 = e.getFieldValue(1002769);
        String phw_yr5 = e.getFieldValue(1002770);
        
        if (isNumeric(phw_price)) {  //percentage value may be empty string or "-"
            standardPercentage.put(skuSuffix, Encoder.parseBigDecimal(phw_price).setScale(3, RoundingMode.HALF_UP));
        }
        if (isNumeric(phw_mon1)) {
            standardPercentage.put(skuSuffix.replace("-DD", "-01"), Encoder.parseBigDecimal(phw_mon1).setScale(3, RoundingMode.HALF_UP));
        }
        if (isNumeric(phw_yr1)) {
            standardPercentage.put(skuSuffix.replace("-DD", "-12"), Encoder.parseBigDecimal(phw_yr1).setScale(3, RoundingMode.HALF_UP));
        }
        if (isNumeric(phw_yr2)) {
            standardPercentage.put(skuSuffix.replace("-DD", "-24"), Encoder.parseBigDecimal(phw_yr2).setScale(3, RoundingMode.HALF_UP));
        }
        if (isNumeric(phw_yr3)) {
            standardPercentage.put(skuSuffix.replace("-DD", "-36"), Encoder.parseBigDecimal(phw_yr3).setScale(3, RoundingMode.HALF_UP));
        }
        if (isNumeric(phw_yr4)) {
            standardPercentage.put(skuSuffix.replace("-DD", "-48"), Encoder.parseBigDecimal(phw_yr4).setScale(3, RoundingMode.HALF_UP));
        }
        if (isNumeric(phw_yr5)) {
            standardPercentage.put(skuSuffix.replace("-DD", "-60"), Encoder.parseBigDecimal(phw_yr5).setScale(3, RoundingMode.HALF_UP));
        }
    }
    
    return standardPercentage;
}

public boolean isNumeric(String str) {
    return str.matches("-?\\d+(\\.\\d+)?");  //match a number with optional '-' and decimal.
}


